# Configuration
$apiUrl = "https://localhost:7123/api/MigrationRequest"

# NOTE: Since the API is protected with [Authorize], you need a valid Azure AD Access Token.
# You can often get one for testing using the Azure CLI if your user has permissions:
# cmd: az account get-access-token --resource "api://<Your-API-Client-ID>" --query accessToken -o tsv
$token = "PASTE_YOUR_BEARER_TOKEN_HERE"

$headers = @{
    "Authorization" = "Bearer $token"
    "Content-Type"  = "application/json"
}

# Dummy Hardware Hash (Truncated for readability, usually much longer)
$dummyHash = ""

$body = @{
    DeviceName   = "PowerShell-Test-Device"
    SerialNumber = "SMBIOS_STRING_INDEX_0"
    HardwareHash = $dummyHash
} | ConvertTo-Json

Write-Host "Sending request to $apiUrl..." -ForegroundColor Cyan

try {
    $response = Invoke-RestMethod -Uri $apiUrl -Method Post -Headers $headers -Body $body -SkipCertificateCheck
    
    Write-Host "Request Successful!" -ForegroundColor Green
    Write-Host "Status: $($response.Status)"
    Write-Host "Message: $($response.Message)"
}
catch {
    Write-Host "Request Failed!" -ForegroundColor Red
    Write-Host "Status Code: $($_.Exception.Response.StatusCode)"
    
    if ($_.Exception.Response) {
        $reader = New-Object System.IO.StreamReader $_.Exception.Response.GetResponseStream()
        Write-Host "Response Body: $($reader.ReadToEnd())" -ForegroundColor Yellow
    }
}